def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    allowed_types = {'lang', 'encoding', 'cache'}
    if info_type not in allowed_types:
        return header
    new_header = header.copy()
    if info_type == 'lang':
        key = 'Accept-Language'
    elif info_type == 'encoding':
        key = 'Accept-Encoding'
    elif info_type == 'cache':
        key = 'Cache-Control'
    new_header[key] = info_content
    return new_header

